    /* ===== Semantic Variables 语义变量（暗色模式）===== */
    --jb-foreground: var(--jb-gray-12);
    --jb-background: var(--jb-gray-2);
    --jb-border: var(--jb-gray-8);

    /* ===== Button State Colors (Dark) 按钮状态颜色 ===== */
    /* Primary */
    --jb-btn-primary-bg: var(--jb-blue-6);
    --jb-btn-primary-bg-hover: var(--jb-blue-5);
    --jb-btn-primary-bg-pressed: var(--jb-blue-4);
    --jb-btn-primary-text: var(--jb-gray-14);
    --jb-btn-primary-ring: var(--jb-blue-6);

    /* Secondary */
    --jb-btn-secondary-bg: var(--jb-gray-5);
    --jb-btn-secondary-bg-hover: var(--jb-gray-6);
    --jb-btn-secondary-bg-pressed: var(--jb-gray-4);
    --jb-btn-secondary-text: var(--jb-gray-12);
    --jb-btn-secondary-border: var(--jb-gray-5);
    --jb-btn-secondary-ring: var(--jb-blue-6);

    /* Disabled */
    --jb-btn-disabled-bg: var(--jb-gray-4);
    --jb-btn-disabled-text: var(--jb-gray-7);

    /* ===== Checkbox State Colors (Dark) 复选框状态颜色 ===== */
    /*
     * 状态矩阵：
     * - 选中维度：unchecked, checked, indeterminate
     * - 交互维度：default, hover, active, focus, invalid, disabled
     */

    /* --- Unchecked 未选中状态 --- */
    /* Default */
    --jb-checkbox-unchecked-bg: transparent;
    --jb-checkbox-unchecked-border: var(--jb-gray-6);
    /* Hover */
    --jb-checkbox-unchecked-bg-hover: transparent;
    --jb-checkbox-unchecked-border-hover: var(--jb-gray-7);
    /* Active/Pressed */
    --jb-checkbox-unchecked-bg-active: transparent;
    --jb-checkbox-unchecked-border-active: var(--jb-gray-8);
    /* Focus */
    --jb-checkbox-unchecked-ring: var(--jb-blue-6);
    /* Invalid */
    --jb-checkbox-unchecked-bg-invalid: transparent;
    --jb-checkbox-unchecked-border-invalid: var(--jb-red-7);
    --jb-checkbox-unchecked-ring-invalid: var(--jb-red-7);
    /* Disabled */
    --jb-checkbox-unchecked-bg-disabled: var(--jb-gray-3);
    --jb-checkbox-unchecked-border-disabled: var(--jb-gray-6);

    /* --- Checked 选中状态 --- */
    /* Default */
    --jb-checkbox-checked-bg: var(--jb-blue-6);
    --jb-checkbox-checked-border: var(--jb-blue-6);
    --jb-checkbox-checked-icon: var(--jb-gray-14);
    /* Hover */
    --jb-checkbox-checked-bg-hover: var(--jb-blue-5);
    --jb-checkbox-checked-border-hover: var(--jb-blue-5);
    /* Active/Pressed */
    --jb-checkbox-checked-bg-active: var(--jb-blue-4);
    --jb-checkbox-checked-border-active: var(--jb-blue-4);
    /* Focus */
    --jb-checkbox-checked-ring: var(--jb-blue-6);
    /* Invalid */
    --jb-checkbox-checked-bg-invalid: var(--jb-blue-6);
    --jb-checkbox-checked-border-invalid: var(--jb-blue-6);
    --jb-checkbox-checked-icon-invalid: var(--jb-gray-14);
    --jb-checkbox-checked-ring-invalid: var(--jb-red-7);
    /* Disabled */
    --jb-checkbox-checked-bg-disabled: var(--jb-gray-3);
    --jb-checkbox-checked-border-disabled: var(--jb-gray-3);
    --jb-checkbox-checked-icon-disabled: var(--jb-gray-8);

    /* --- Indeterminate 不确定状态 (继承 checked 的大部分样式) --- */
    --jb-checkbox-indeterminate-bg: var(--jb-blue-6);
    --jb-checkbox-indeterminate-border: var(--jb-blue-6);
    --jb-checkbox-indeterminate-icon: var(--jb-gray-14);
    --jb-checkbox-indeterminate-bg-hover: var(--jb-blue-5);
    --jb-checkbox-indeterminate-bg-active: var(--jb-blue-4);
    --jb-checkbox-indeterminate-bg-disabled: var(--jb-gray-3);
    --jb-checkbox-indeterminate-icon-disabled: var(--jb-gray-8);

    /* ===== Radio Button State Colors (Dark) 单选按钮状态颜色 ===== */
    /*
     * 状态矩阵：
     * - 选中维度：unchecked, checked
     * - 交互维度：default, hover, active, focus, invalid, disabled
     */

    /* --- Unchecked 未选中状态 --- */
    /* Default */
    --jb-radio-unchecked-bg: var(--jb-gray-3);
    --jb-radio-unchecked-border: var(--jb-gray-6);
    /* Hover */
    --jb-radio-unchecked-bg-hover: var(--jb-gray-4);
    --jb-radio-unchecked-border-hover: var(--jb-gray-7);
    /* Active/Pressed */
    --jb-radio-unchecked-bg-active: var(--jb-gray-5);
    --jb-radio-unchecked-border-active: var(--jb-gray-8);
    /* Focus */
    --jb-radio-unchecked-ring: var(--jb-blue-6);
    /* Invalid */
    --jb-radio-unchecked-bg-invalid: var(--jb-gray-3);
    --jb-radio-unchecked-border-invalid: var(--jb-red-7);
    --jb-radio-unchecked-ring-invalid: var(--jb-red-7);
    /* Disabled */
    --jb-radio-unchecked-bg-disabled: var(--jb-gray-4);
    --jb-radio-unchecked-border-disabled: var(--jb-gray-5);

    /* --- Checked 选中状态 --- */
    /* Default */
    --jb-radio-checked-bg: var(--jb-gray-3);
    --jb-radio-checked-border: var(--jb-blue-6);
    --jb-radio-checked-indicator: var(--jb-blue-6);
